template <typename T>
__device__ inline void atomicAddCustom(T* addr, T val);

template <>
__device__ inline void atomicAddCustom<float>(float* addr, float val) {
  atomicAdd(addr, val);
}

template <>
__device__ inline void atomicAddCustom<int>(int* addr, int val) {
  atomicAdd(addr, val);
}

template <>
__device__ inline void atomicAddCustom<double>(double* addr, double val) {
#if __CUDA_ARCH__ >= 600
  atomicAdd(addr, val);
#else
  unsigned long long int* address_as_ull =
      reinterpret_cast<unsigned long long int*>(addr);
  unsigned long long int old = *address_as_ull, assumed;
  do {
    assumed = old;
    old = atomicCAS(address_as_ull, assumed,
                    __double_as_longlong(val + __longlong_as_double(assumed)));
  } while (assumed != old);
#endif
}

#ifdef BASELINE_IMPL
template <typename Element, unsigned int compute_iterations,
          unsigned int static_chunk_size>
__global__ void bench_block_kernel(Element* src, Element* partial,
                                   size_t num_chunks) {
  size_t chunk_idx = static_cast<size_t>(blockIdx.x) * blockDim.x + threadIdx.x;
  if (chunk_idx >= num_chunks) return;

  Element* data = src + chunk_idx * static_chunk_size;
  Element sum = 0;
  Element f = data[0];

  for (size_t i = 0; i < static_chunk_size; i++) {
    Element t = data[i];
    for (size_t j = 0; j < compute_iterations; j++) {
      t = t * t + f;
    }
    sum += t;
  }

  partial[chunk_idx] = sum;
}
#else
template <typename Element, unsigned int compute_iterations,
          unsigned int static_chunk_size>
__global__ void bench_block_kernel(Element* src, Element* partial,
                                   size_t num_chunks) {
  size_t chunk_idx = static_cast<size_t>(blockIdx.x) * blockDim.x + threadIdx.x;
  if (chunk_idx >= num_chunks) return;

  Element* data = src + chunk_idx * static_chunk_size;
  Element sum = 0;

  Element f0 = data[0], f1 = data[1], f2 = data[2], f3 = data[3];
  Element f4 = data[4], f5 = data[5], f6 = data[6], f7 = data[7];

  for (size_t i = 0; i < static_chunk_size; i++) {
    Element d = data[i];
    Element t0 = d, t1 = d, t2 = d, t3 = d, t4 = d, t5 = d, t6 = d, t7 = d;

#pragma unroll
    for (size_t j = 0; j < (compute_iterations / 8); j++) {
      t0 = t0 * t0 + f0;
      t1 = t1 * t1 + f1;
      t2 = t2 * t2 + f2;
      t3 = t3 * t3 + f3;
      t4 = t4 * t4 + f4;
      t5 = t5 * t5 + f5;
      t6 = t6 * t6 + f6;
      t7 = t7 * t7 + f7;
    }

    if (compute_iterations % 8 > 0) t0 = t0 * t0 + f0;
    if (compute_iterations % 8 > 1) t1 = t1 * t1 + f1;
    if (compute_iterations % 8 > 2) t2 = t2 * t2 + f2;
    if (compute_iterations % 8 > 3) t3 = t3 * t3 + f3;
    if (compute_iterations % 8 > 4) t4 = t4 * t4 + f4;
    if (compute_iterations % 8 > 5) t5 = t5 * t5 + f5;
    if (compute_iterations % 8 > 6) t6 = t6 * t6 + f6;

    sum += (t0 + t1 + t2 + t3 + t4 + t5 + t6 + t7);
  }

  partial[chunk_idx] = sum;
}
#endif

template <typename Element>
__global__ void reduce_kernel(const Element* partial, size_t n, Element* out) {
  extern __shared__ unsigned char smem[];
  Element* sdata = reinterpret_cast<Element*>(smem);

  unsigned int tid = threadIdx.x;
  size_t idx = static_cast<size_t>(blockIdx.x) * blockDim.x + tid;
  size_t stride = static_cast<size_t>(gridDim.x) * blockDim.x;

  Element sum = 0;
  for (size_t i = idx; i < n; i += stride) {
    sum += partial[i];
  }

  sdata[tid] = sum;
  __syncthreads();

  for (unsigned int s = blockDim.x / 2; s > 0; s >>= 1) {
    if (tid < s) sdata[tid] += sdata[tid + s];
    __syncthreads();
  }

  if (tid == 0) {
    atomicAddCustom(out, sdata[0]);
  }
}

template <typename Element>
__global__ void write_first_kernel(Element* src, const Element* value) {
  if (blockIdx.x == 0 && threadIdx.x == 0) {
    *src = *value;
  }
}

template <typename Element, unsigned int compute_iterations>
size_t bench(size_t len, const Element seed1, const Element seed2, Element* src) {
  (void)seed1;
  (void)seed2;

  constexpr size_t static_chunk_size = 4096;
  if (len == 0) return 0;

  const size_t num_chunks = len / static_chunk_size;
  if (num_chunks == 0) return len;

  Element* d_partial = nullptr;
  Element* d_sum = nullptr;

  CUDA_SAFE_CALL(cudaMalloc(&d_partial, num_chunks * sizeof(Element)));
  CUDA_SAFE_CALL(cudaMalloc(&d_sum, sizeof(Element)));
  CUDA_SAFE_CALL(cudaMemset(d_sum, 0, sizeof(Element)));

  const int block_size = 128;
  const int grid_size =
      static_cast<int>((num_chunks + block_size - 1) / block_size);

  bench_block_kernel<Element, compute_iterations, static_chunk_size>
      <<<grid_size, block_size>>>(src, d_partial, num_chunks);
  CUDA_SAFE_CALL(cudaGetLastError());

  const int red_block = 256;
  int red_grid = static_cast<int>((num_chunks + red_block - 1) / red_block);
  if (red_grid > 1024) red_grid = 1024;
  if (red_grid < 1) red_grid = 1;

  reduce_kernel<Element><<<red_grid, red_block, red_block * sizeof(Element)>>>(
      d_partial, num_chunks, d_sum);
  CUDA_SAFE_CALL(cudaGetLastError());

  write_first_kernel<Element><<<1, 1>>>(src, d_sum);
  CUDA_SAFE_CALL(cudaGetLastError());

  CUDA_SAFE_CALL(cudaDeviceSynchronize());

  CUDA_SAFE_CALL(cudaFree(d_sum));
  CUDA_SAFE_CALL(cudaFree(d_partial));

  return len;
}

auto runbench_warmup(void* c, size_t size) {
  const size_t num_elements = size / sizeof(double);
  auto timer_start = benchmark_clock::now();

  double* ptr = reinterpret_cast<double*>(c);
  bench<double, 16>(num_elements, 1.0, -1.0, ptr);

  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration)
      .count();
}

template <typename Op>
auto measure_operation(Op op) {
  auto timer_start = benchmark_clock::now();
  op();
  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration)
             .count() /
         1000.0;
}

template <typename Op>
auto benchmark_omp(Op op) {
  constexpr int total_runs = 20;
  constexpr int total_half_thread_runs = 10;

  auto duration = op();
  std::vector<decltype(duration)> measurements;

  for (int i = 1; i < total_runs; i++) {
    duration = op();
    measurements.push_back(duration);
  }

  if (base_cuda_get_max_threads > 1) {
    for (int i = 1; i < total_half_thread_runs; i++) {
      duration = op();
      measurements.push_back(duration);
    }
  }

  return *std::min_element(std::begin(measurements), std::end(measurements));
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t memory_space, int compute_iterations)
      : memory_space_{memory_space}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements * compute_iterations_ * 2 * 1 + total_elements - 1;
    return computations;
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

template <unsigned int compute_iterations>
void runbench(void* c, size_t size) {
  ComputeSpace cs{size, static_cast<int>(compute_iterations)};

  float* c_as_float = reinterpret_cast<float*>(c);
  auto kernel_time_mad_sp = benchmark_omp([&] {
    return measure_operation([&] {
      bench<float, compute_iterations>(cs.element_count<float>(), 1.f, -1.f,
                                       c_as_float);
    });
  });

  double* c_as_double = reinterpret_cast<double*>(c);
  auto kernel_time_mad_dp = benchmark_omp([&] {
    return measure_operation([&] {
      bench<double, compute_iterations>(cs.element_count<double>(), 1., -1.,
                                        c_as_double);
    });
  });

  int* c_as_int = reinterpret_cast<int*>(c);
  auto kernel_time_mad_int = benchmark_omp([&] {
    return measure_operation([&] {
      bench<int, compute_iterations>(cs.element_count<int>(), 1, -1, c_as_int);
    });
  });

  const auto computations_sp = cs.compute_ops<float>();
  const auto computations_dp = cs.compute_ops<double>();
  const auto computations_int = cs.compute_ops<int>();
  const auto memory_traffic = cs.memory_traffic();

  const auto setw = std::setw;
  const auto setprecision = std::setprecision;
  std::cout << std::fixed << "         " << std::setw(4) << compute_iterations
            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_sp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_sp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_sp) / kernel_time_mad_sp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_sp *
                   1000. / (1000. * 1000. * 1000.)

            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_dp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_dp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_dp) / kernel_time_mad_dp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_dp *
                   1000. / (1000. * 1000. * 1000.)

            << ",  " << setw(8) << setprecision(3)
            << static_cast<double>(computations_int) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_int << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_int) / kernel_time_mad_int *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_int *
                   1000. / (1000. * 1000. * 1000.)

            << std::endl;
}

template <unsigned int compute_iterations>
void runbench_range(void* cd, size_t size) {
  runbench<compute_iterations>(cd, size);
}

template <unsigned int j1, unsigned int j2, unsigned int... Args>
void runbench_range(void* cd, size_t size) {
  runbench_range<j1>(cd, size);
  runbench_range<j2, Args...>(cd, size);
}

extern "C" void mixbenchGPU(double* c, long size) {
  size_t bytes = static_cast<size_t>(size) * sizeof(double);

  cudaDeviceProp prop{};
  int dev = 0;
  CUDA_SAFE_CALL(cudaGetDevice(&dev));
  CUDA_SAFE_CALL(cudaGetDeviceProperties(&prop, dev));
  base_cuda_get_max_threads = prop.multiProcessorCount;

  void* d_buf = nullptr;
  CUDA_SAFE_CALL(cudaMalloc(&d_buf, bytes));
  CUDA_SAFE_CALL(cudaMemset(d_buf, 0, bytes));

  std::cout << "----------------------------------------------------------"
               "---- CSV data "
               "----------------------------------------------------------"
               "----"
            << std::endl;
  std::cout << "Experiment ID, Single Precision ops,,,,              Double "
               "precision ops,,,,              Integer operations,,, "
            << std::endl;
  std::cout << "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, "
               "Flops/byte, ex.time,  GFLOPS, GB/sec, Iops/byte, ex.time,   "
               "GIOPS, GB/sec"
            << std::endl;

  runbench_warmup(d_buf, bytes);

  runbench_range<0, 1, 2, 3, 4, 6, 8, 12, 16, 20, 24, 28, 32, 40, 6 * 8, 7 * 8,
                 8 * 8, 10 * 8, 13 * 8, 15 * 8, 16 * 8, 20 * 8, 24 * 8, 32 * 8,
                 40 * 8, 64 * 8>(d_buf, bytes);

  std::cout << "---------------------------------------------------------------"
               "---------------------------------------------------------------"
            << std::endl;

  CUDA_SAFE_CALL(cudaMemcpy(c, d_buf, bytes, cudaMemcpyDeviceToHost));
  CUDA_SAFE_CALL(cudaFree(d_buf));
